```
    int counter = 0;
    int pid, status;
    void handlerl(int sig) {
        counter += 1;
        printf("%d", counter);
        int ppid = getppid(); // get pid
        kill(ppid, SIGUSR2);
    }
    void handler2(int sig) {
        counter += 7;
        printf("%d", counter);
    }
    int main(){
        signal(SIGUSR1, handler 1);
        signal(SIGUSR2, handler2);
        if(pid = fork()) {
            kill(pid, SIGUSR1);
        } else {
            printf("%d", counter);
        }
        return 0;
}
